func solve(grid [][]int64, k int64) int64 {
    m := len(grid)
    if m == 0 {
        return 0
    }
    n := len(grid[0])
    visited := make([][]bool, m)
    for i := range visited {
        visited[i] = make([]bool, n)
    }
    directions := [][2]int{{0, 1}, {1, 0}, {0, -1}, {-1, 0}}
    count := int64(0)
    for i := 0; i < m; i++ {
        for j := 0; j < n; j++ {
            if grid[i][j] > 0 && !visited[i][j] {
                queue := [][]int{{i, j}}
                visited[i][j] = true
                sum := grid[i][j]
                for len(queue) > 0 {
                    x, y := queue[0][0], queue[0][1]
                    queue = queue[1:]
                    for _, dir := range directions {
                        nx := x + dir[0]
                        ny := y + dir[1]
                        if nx >= 0 && nx < m && ny >= 0 && ny < n && !visited[nx][ny] && grid[nx][ny] > 0 {
                            visited[nx][ny] = true
                            sum += grid[nx][ny]
                            queue = append(queue, []int{nx, ny})
                        }
                    }
                }
                if sum%k == 0 {
                    count++
                }
            }
        }
    }
    return count
}
